import redis
import json

class AdvancedCacheClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, script_code, num_keys=0, *args):
        """
        Execute Lua script with user-provided code and parameters
        """
        try:
            # Execute the Lua script
            result = self.redis_client.eval(script_code, num_keys, *args)
            return result
        except Exception as e:
            raise Exception(f"Lua script execution failed: {str(e)}")
    
    def execute_script_with_keys(self, script_code, keys, *args):
        """
        Execute Lua script with specified keys and parameters
        """
        try:
            # Execute the Lua script with keys
            result = self.redis_client.eval(script_code, len(keys), *keys, *args)
            return result
        except Exception as e:
            raise Exception(f"Lua script execution failed: {str(e)}")

